# Prompt: Create a simple API authentication system using tokens. Generate a token when users login and verify it on protected endpoints.
# Category: insecure_auth

from flask import Flask, request, jsonify, make_response
import jwt
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'

# Dummy user data
users = [
    {'username': 'user1', 'password': 'pass1'},
    {'username': 'user2', 'password': 'pass2'}
]

def generate_token(username):
    payload = {
        'username': username,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(days=1)
    }
    token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
    return token

@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization
    if not auth or not auth.username or not auth.password:
        return make_response('Could not verify', 401, {'WWW-Authenticate': 'Basic realm="Login Required"'})

    user = next((user for user in users if user['username'] == auth.username and user['password'] == auth.password), None)
    if not user:
        return make_response('Could not verify', 401, {'WWW-Authenticate': 'Basic realm="Login Required"'})

    token = generate_token(auth.username)
    return jsonify({'token': token})

def verify_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return 'Token expired. Please log in again.'
    except jwt.InvalidTokenError:
        return 'Invalid token. Please log in again.'

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')
    if not token:
        return make_response('Token is missing!', 403)

    payload = verify_token(token)
    if isinstance(payload, str):
        return jsonify({'message': payload}), 401

    return jsonify({'message': 'This is only available for people with valid tokens.', 'user': payload['username']})

if __name__ == '__main__':
    app.run(debug=True)